ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?albumname ?year ?month WHERE {
  ?albums a :Album .
  ?songs a :Song .
  ?songs p:hasAlbums ?albums .
  ?albums p:AlbumName ?albumname .
  ?albums p:Year ?year .
  ?albums p:Month ?month .
  ?songs p:Duration ?duration_o .
}
ORDER BY DESC(?duration_o)
LIMIT 1 }
  component: { SELECT ?albumname ?month WHERE {
  ?albums a :Album .
  ?songs a :Song .
  ?songs p:hasAlbums ?albums .
  ?albums p:AlbumName ?albumname .
  ?albums p:Month ?month .
  ?songs p:Duration ?duration_o .
}
ORDER BY DESC(?duration_o)
LIMIT 1 }
  component_2: { SELECT ?albumname ?year WHERE {
  ?albums a :Album .
  ?songs a :Song .
  ?songs p:hasAlbums ?albums .
  ?albums p:AlbumName ?albumname .
  ?albums p:Year ?year .
  ?songs p:Duration ?duration_o .
}
ORDER BY DESC(?duration_o)
LIMIT 1 }
}
